import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.y1bVONfd.js";const u=JSON.parse('{"title":"告警中心","description":"告警规则和通知渠道配置","frontmatter":{"title":"告警中心","description":"告警规则和通知渠道配置"},"headers":[],"relativePath":"zh/guide/alerting.md","filePath":"zh/guide/alerting.md"}'),o={name:"zh/guide/alerting.md"};function h(i,t,n,l,c,s){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="告警中心" tabindex="-1">告警中心 <a class="header-anchor" href="#告警中心" aria-label="Permalink to &quot;告警中心&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>告警引擎每分钟评估规则，满足条件时发送通知。</p><h2 id="告警规则" tabindex="-1">告警规则 <a class="header-anchor" href="#告警规则" aria-label="Permalink to &quot;告警规则&quot;">​</a></h2><h3 id="高错误率告警" tabindex="-1">高错误率告警 <a class="header-anchor" href="#高错误率告警" aria-label="Permalink to &quot;高错误率告警&quot;">​</a></h3><p>Provider 错误率超过阈值时触发：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>阈值</td><td>错误率（如 0.1 = 10%）</td></tr><tr><td>窗口</td><td>评估时间窗口（分钟）</td></tr></tbody></table><h3 id="额度预警" tabindex="-1">额度预警 <a class="header-anchor" href="#额度预警" aria-label="Permalink to &quot;额度预警&quot;">​</a></h3><p>Token 剩余额度低于阈值时触发：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>阈值</td><td>剩余百分比（如 0.2 = 20%）</td></tr><tr><td>范围</td><td>token 或 organization</td></tr></tbody></table><h3 id="provider-断开告警" tabindex="-1">Provider 断开告警 <a class="header-anchor" href="#provider-断开告警" aria-label="Permalink to &quot;Provider 断开告警&quot;">​</a></h3><p>Provider 持续失败时触发：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>最大重试</td><td>连续失败次数</td></tr><tr><td>窗口</td><td>评估时间窗口（分钟）</td></tr></tbody></table><h2 id="告警级别" tabindex="-1">告警级别 <a class="header-anchor" href="#告警级别" aria-label="Permalink to &quot;告警级别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>级别</th><th>颜色</th><th>行为</th></tr></thead><tbody><tr><td><code>critical</code></td><td>红色</td><td>全部渠道通知</td></tr><tr><td><code>warning</code></td><td>黄色</td><td>通知，不升级</td></tr><tr><td><code>info</code></td><td>蓝色</td><td>仅通知</td></tr></tbody></table><h2 id="通知渠道" tabindex="-1">通知渠道 <a class="header-anchor" href="#通知渠道" aria-label="Permalink to &quot;通知渠道&quot;">​</a></h2><h3 id="邮件" tabindex="-1">邮件 <a class="header-anchor" href="#邮件" aria-label="Permalink to &quot;邮件&quot;">​</a></h3><p>在 <strong>系统设置</strong> → <strong>告警设置</strong> 中配置 SMTP。</p><h3 id="微信" tabindex="-1">微信 <a class="header-anchor" href="#微信" aria-label="Permalink to &quot;微信&quot;">​</a></h3><p>使用 ServerChan（方糖推送）实现微信通知。</p><h2 id="冷却" tabindex="-1">冷却 <a class="header-anchor" href="#冷却" aria-label="Permalink to &quot;冷却&quot;">​</a></h2><p>默认冷却时间 5 分钟，避免告警轰炸。</p>',22)])])}const p=a(o,[["render",h]]);export{u as __pageData,p as default};
